There is a miscompilation issue report in InstCombine, InstructionSimplify: 

It's not ok to fold `frexp(frexp(x))` to `frexp(x)`:

```llvm
; Transforms/InstSimplify/frexp.ll

define {float, i32} @frexp_frexp(float %x) {
  %frexp0 = frexp float %x
  %frexp0.0 = extractvalue {float, i32} %frexp0, 0
  %frexp1 = frexp float %frexp0.0
  ret {float, i32} %frexp1
}
=>
define {float, i32} @frexp_frexp(float %x) {
  %frexp0 = frexp float %x
  ret {float, i32} %frexp0
}
Transformation doesn't verify!

ERROR: Value mismatch

Example:
float %x = #x0000000a (0.000000000000?)

Source:
{float, i32} %frexp0 = { #x3f200000 (0.625), #xffffff6f (4294967151, -145) }
float %frexp0.0 = #x3f200000 (0.625)
{float, i32} %frexp1 = { #x3f200000 (0.625), #x00000000 (0) }

Target:
{float, i32} %frexp0 = { #x3f200000 (0.625), #xffffff6f (4294967151, -145) }
Source value: { #x3f200000 (0.625), #x00000000 (0) }
Target value: { #x3f200000 (0.625), #xffffff6f (4294967151, -145) }
```

cc @arsenm

The maintainers proposed the following patch to fix the issue:

commit f9783c559f16991c19924898357edb9240a5f0aa
Author: Iris Shi <0.0@owo.li>
Date:   Thu May 8 00:37:46 2025 +0800

    [InstCombine] Fix `frexp(frexp(x)) -> frexp(x)` fold (#138837)

    Fixes #138819

    When frexp is applied twice, the second result should be zero.

diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 5a2943de9066..85e3be9cc45c 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -6377,15 +6377,6 @@ static Value *simplifyUnaryIntrinsic(Function *F, Value *Op0,
     if (isSplatValue(Op0))
       return Op0;
     break;
-  case Intrinsic::frexp: {
-    // Frexp is idempotent with the added complication of the struct return.
-    if (match(Op0, m_ExtractValue<0>(m_Value(X)))) {
-      if (match(X, m_Intrinsic<Intrinsic::frexp>(m_Value())))
-        return X;
-    }
-
-    break;
-  }
   default:
     break;
   }
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 4716eeb60f0c..3d35bf753c40 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3811,6 +3811,21 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     }
     break;
   }
+  case Intrinsic::frexp: {
+    Value *X;
+    // The first result is idempotent with the added complication of the struct
+    // return, and the second result is zero because the value is already
+    // normalized.
+    if (match(II->getArgOperand(0), m_ExtractValue<0>(m_Value(X)))) {
+      if (match(X, m_Intrinsic<Intrinsic::frexp>(m_Value()))) {
+        X = Builder.CreateInsertValue(
+            X, Constant::getNullValue(II->getType()->getStructElementType(1)),
+            1);
+        return replaceInstUsesWith(*II, X);
+      }
+    }
+    break;
+  }
   default: {
     // Handle target specific intrinsics
     std::optional<Instruction *> V = targetInstCombineIntrinsic(*II);


